module comparator_4bit (obf_a, b, gt, lt, eq);
   input [3:0] obf_a;
   input [3:0] b;
   output gt;
   output lt;
   output eq;

   reg gt;
   reg lt;
   reg eq;

always @(*) begin
    if (obf_a > b) begin
        gt = 1;
        lt = 0;
        eq = 0;
    end else if (obf_a < b) begin
        gt = 0;
        lt = 1;
        eq = 0;
    end else begin
        gt = 0;
        lt = 0;
        eq = 1;
    end
end

endmodule
